import{_ as p,C as s,c as i,o as u,ag as l,j as t,G as a,w as n,a as o}from"./chunks/framework.D4Vqf8I7.js";const c=JSON.parse('{"title":"PUNK0 - A FUNCTION COMPOSITION CARD GAME","description":"","frontmatter":{},"headers":[],"relativePath":"docs/wi/games/board/punk0.md","filePath":"docs/wi/games/board/punk0.md","lastUpdated":1779891150000}'),k={name:"docs/wi/games/board/punk0.md"};function g(d,r,m,h,f,b){const e=s("font");return u(),i("div",null,[r[20]||(r[20]=l('<h1 id="punk0-a-function-composition-card-game" tabindex="-1">PUNK0 - A FUNCTION COMPOSITION CARD GAME <a class="header-anchor" href="#punk0-a-function-composition-card-game" aria-label="Permalink to &quot;PUNK0 - A FUNCTION COMPOSITION CARD GAME&quot;">​</a></h1><p><a href="https://punkx.org/punk0/" target="_blank" rel="noreferrer">https://punkx.org/punk0/</a></p><p>Что-то вроде UNO для разработчиков, но со стратегией.</p><p><strong>Выход</strong> каждой карты — это <strong>вход</strong> для другой карты.</p><p><a href="https://punkx.org/punk0/photos/deck-large.jpg" target="_blank" rel="noreferrer"><img src="https://punkx.org/punk0/photos/deck.jpg" alt="Deck"></a><a href="https://punkx.org/punk0/photos/deck1-large.jpg" target="_blank" rel="noreferrer"><img src="https://punkx.org/punk0/photos/deck1.jpg" alt="Deck 1"></a><a href="https://punkx.org/punk0/photos/deck2-large.jpg" target="_blank" rel="noreferrer"><img src="https://punkx.org/punk0/photos/deck2.jpg" alt="Deck 2"></a><a href="https://punkx.org/punk0/photos/deck3-large.jpg" target="_blank" rel="noreferrer"><img src="https://punkx.org/punk0/photos/deck3.jpg" alt="Deck 3"></a></p><p><s><strong>Купить сейчас: €5,00 EUR</strong></s> [ распродано ]</p><ul><li>распечатайте сами: <a href="punk0-cards.pdf">punk0-cards.pdf</a>, <a href="punk0-box.pdf">punk0-box.pdf</a>, <a href="punk0-box-cc.pdf">punk0-box-cc.pdf (лицензия CC BY 4.0)</a></li><li>код: <a href="https://github.com/jackdoe/programming-for-kids/tree/master/projects/punk0" target="_blank" rel="noreferrer">punk0</a></li><li>автор: <a href="https://github.com/jackdoe" target="_blank" rel="noreferrer">github.com/jackdoe</a></li><li>соавтор: <a href="https://punkjazz.org/jackie" target="_blank" rel="noreferrer">Jackie</a> (помогала с тестированием и идеями)</li><li>контакт: <a href="mailto:punkx@fastmail.com" target="_blank" rel="noreferrer">punkx@fastmail.com</a></li><li>лицензия: CC BY 4.0, но изображение обложки лицензировано по лицензии Shutterstock до 500 000 экземпляров, поэтому если вы печатаете такое количество, пожалуйста, используйте версию с лицензией CC BY 4.0</li></ul><hr><h2 id="описание-игры" tabindex="-1">Описание игры <a class="header-anchor" href="#описание-игры" aria-label="Permalink to &quot;Описание игры&quot;">​</a></h2><p>На каждой карте изображена функция, написанная на 4 языках: C, Go, Python, JS. Игра начинается со списка <code>[0, 0, 0, 0]</code>. Вы должны сыграть либо ту же функцию на другом языке, либо любую функцию на том же языке, что и предыдущая карта. Каждая карта принимает список и возвращает список. Также есть карты <strong>punk0, punk1, punk2, punk3</strong>, которые указывают, что нужно сделать в зависимости от соответствующего индекса списка.</p><p><strong>Пример:</strong> если список становится <code>[0, **-2**, 1, 3]</code>, и вы играете карту <strong>punk1(x)</strong>, которая работает с индексом 1 списка (в данном случае значение <code>-2</code>), вы должны сыграть ещё 2 валидные карты за один ход или взять карты из колоды.</p><hr><h2 id="правила" tabindex="-1"><mark>ПРАВИЛА</mark> <a class="header-anchor" href="#правила" aria-label="Permalink to &quot;&lt;mark&gt;ПРАВИЛА&lt;/mark&gt;&quot;">​</a></h2><ul><li>Стартовый список: <strong>[0, 0, 0, 0]</strong></li><li>Каждый игрок получает 8 карт, самый молодой игрок ходит первым и может сыграть любую карту.</li><li>Игроки могут сыграть либо ту же функцию на другом языке, либо любую функцию на том же языке, что и предыдущая карта.</li><li>Игроки обязаны сыграть подходящую карту, если она у них есть; в противном случае они берут одну карту из колоды.</li><li>Если игроку требуется взять одну или несколько карт в результате действия карты punk() или потому что у него нет подходящей карты, он должен сыграть одну из взятых карт, если она является валидной.</li><li>Первый игрок, избавившийся от всех карт, выигрывает.</li></ul><blockquote><p><strong>Облегчённый режим:</strong> играйте так, будто инкремент/декремент, rotate_left/rotate_right, punk0/punk1/punk2/punk3 — это одна и та же функция.</p></blockquote><hr><h2 id="карты-punk" tabindex="-1"><mark>КАРТЫ PUNK</mark> <a class="header-anchor" href="#карты-punk" aria-label="Permalink to &quot;&lt;mark&gt;КАРТЫ PUNK&lt;/mark&gt;&quot;">​</a></h2>',17)),t("ul",null,[t("li",null,[a(e,{color:"navy"},{default:n(()=>r[0]||(r[0]=[o("**punk0():**")])),_:1,__:[0]}),r[15]||(r[15]=t("br",null,null,-1)),r[16]||(r[16]=t("p",null,"Карта определяет следующее действие на основе первого элемента (индекс 0) списка.",-1)),t("ul",null,[t("li",null,[r[2]||(r[2]=t("strong",null,"Если",-1)),r[3]||(r[3]=o(" значение ")),r[4]||(r[4]=t("strong",null,"первого",-1)),r[5]||(r[5]=o(" элемента равно ")),a(e,{color:"red"},{default:n(()=>r[1]||(r[1]=[o("нулю")])),_:1,__:[1]}),r[6]||(r[6]=o(", следующий игрок пропускает ход."))]),t("li",null,[r[8]||(r[8]=t("strong",null,"Если",-1)),r[9]||(r[9]=o(" значение ")),a(e,{color:"red"},{default:n(()=>r[7]||(r[7]=[o("отрицательное")])),_:1,__:[7]}),r[10]||(r[10]=o(", текущий игрок должен сыграть ровно N карт за один ход, где N — абсолютное значение элемента. Если он не может сыграть N карт, он берёт карты из колоды."))]),t("li",null,[r[12]||(r[12]=t("strong",null,"Если",-1)),r[13]||(r[13]=o(" значение ")),a(e,{color:"red"},{default:n(()=>r[11]||(r[11]=[o("положительное")])),_:1,__:[11]}),r[14]||(r[14]=o(", следующий игрок должен взять N карт из колоды, где N — значение элемента, если только у него нет карты punk0, в этом случае он может передать штраф следующему игроку."))])])]),t("li",null,[a(e,{color:"navy"},{default:n(()=>r[17]||(r[17]=[o("**punk1() punk2() punk3():**")])),_:1,__:[17]}),r[18]||(r[18]=t("br",null,null,-1)),r[19]||(r[19]=t("p",null,"То же самое, что punk0(), но используется соответствующий индекс списка: punk1 — индекс 1 и так далее.",-1))])]),r[21]||(r[21]=l('<hr><h2 id="пример-раунда" tabindex="-1">Пример раунда <a class="header-anchor" href="#пример-раунда" aria-label="Permalink to &quot;Пример раунда&quot;">​</a></h2><p><a href="https://punkx.org/punk0/photos/example1-large.jpg" target="_blank" rel="noreferrer"><img src="https://punkx.org/punk0/photos/example1.jpg" alt="Example"></a></p><h3 id="краткое-объяснение-игры" tabindex="-1">Краткое объяснение игры: <a class="header-anchor" href="#краткое-объяснение-игры" aria-label="Permalink to &quot;Краткое объяснение игры:&quot;">​</a></h3>',4)),r[22]||(r[22]=t("iframe",{width:"560",height:"315",src:"https://www.youtube-nocookie.com/embed/DV_VD1Dis78",title:"YouTube video player",frameborder:"0",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share",allowfullscreen:""},null,-1)),r[23]||(r[23]=t("h3",{id:"пример-партии",tabindex:"-1"},[o("Пример партии: "),t("a",{class:"header-anchor",href:"#пример-партии","aria-label":'Permalink to "Пример партии:"'},"​")],-1)),r[24]||(r[24]=t("iframe",{width:"560",height:"315",src:"https://www.youtube-nocookie.com/embed/XMJkH_A-KCY",title:"YouTube video player",frameborder:"0",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share",allowfullscreen:""},null,-1)),r[25]||(r[25]=l('<hr><blockquote><p>Я работал над этой игрой в первую очередь для того, чтобы показать дочери, что знание множества языков программирования не так важно — главное понимать, <strong>как всё устроено</strong>, <strong>что они представляют</strong> и особенно <strong>как компьютер их воспринимает</strong>. Также чтобы начать формировать интуицию относительно вращения и манипуляции участками памяти.</p></blockquote><h2 id="символы-и-цвета" tabindex="-1"><mark>Символы и цвета</mark> <a class="header-anchor" href="#символы-и-цвета" aria-label="Permalink to &quot;&lt;mark&gt;Символы и цвета&lt;/mark&gt;&quot;">​</a></h2><ul><li>Демоны на обложке представляют 4 языка: <strong>C</strong> — череп, <strong>Go</strong> — маска, а две рыбы — <strong>JS</strong> и <strong>Python</strong>. Мне кажется забавным, что всё, что мы делаем, вращается вокруг C: чем дальше вы удаляетесь (например, PyTorch), тем сильнее вас тянет обратно. Может быть, однажды мы наберём достаточную скорость для побега и создадим новые парадигмы, которые не будут просто C с добавлением «сахара».</li><li>Кельтский узор на задней стороне коробки символизирует, как всё в компьютерных науках взаимосвязано, и как знания и понимание можно строить разными путями (<a href="https://www.youtube.com/watch?v=zesyeIvbjLQ" target="_blank" rel="noreferrer">Richard Feynman - The Relation of Mathematics to Physics</a>).</li><li>Цвета карт: <ul><li><strong>C</strong>: я постарался воссоздать стиль <a href="https://winworldpc.com/product/borland-c/30">Borland C++ 3.1 для DOS</a> — это очень близко моему сердцу, я считаю, что это, возможно, лучшая среда разработки, которой я когда-либо пользовался.</li><li><strong>Go</strong>: использованы цвета <a href="https://en.wikipedia.org/wiki/Acme_(text_editor)">ACME</a>, но с добавлением цвета для ключевых слов. Хотя я не использую подсветку синтаксиса, я думаю, людям будет странно видеть код вообще без цветов.</li><li><strong>JS</strong>: вдохновлено тёмной темой HackerRank.</li><li><strong>Python</strong>: вдохновлено светлой темой GitHub.</li></ul></li><li><strong>Неизменяемость</strong>: все функции возвращают новый список — мне казалось странным, если бы карты мутировали входной список.</li></ul><hr><h2 id="благодарности" tabindex="-1"><mark>Благодарности</mark> <a class="header-anchor" href="#благодарности" aria-label="Permalink to &quot;&lt;mark&gt;Благодарности&lt;/mark&gt;&quot;">​</a></h2><p>Это, возможно, 30-я версия игры, и она действительно интересная (на мой взгляд). Мы напечатали и протестировали множество версий, и я хочу поблагодарить друзей, которые помогли мне в тестировании: Ronen, Peter, Maarten, Angel, Mattias, Tarek, Deo, Evanji, Melore, Aymeric и многих других, кого я мучил скучными версиями 😄</p><p>Вот некоторые из неудачных попыток:</p><p><a href="https://punkx.org/punk0/photos/attempts.jpg" target="_blank" rel="noreferrer"><img src="https://punkx.org/punk0/photos/attempts.jpg" alt="Attempts"></a></p><blockquote><p><strong>P.S.:</strong> Для создания карт не использовались LLM, но я применял ChatGPT, чтобы помочь переформулировать правила, так как английский — не мой родной язык, и мне бывает сложно выражать идеи, особенно когда пространство так ограничено.</p></blockquote>',10))])}const C=p(k,[["render",g]]);export{c as __pageData,C as default};
